    private int index = 7; // end of (first) permutation

    public char nextLetter() {
        char letter = PERMUTATIONS.charAt(index);
        // end of permutation?
        if (letter == ' ') {
            // start new permutation
            index = (Zufall.nextInt() % 5040) * 8;
            letter = PERMUTATIONS.charAt(index);
        }
        ++index;
        return letter;
    }
